-- Drop existing tables to ensure a clean state (as requested for the next deployment)
DROP TABLE IF EXISTS bank_category_conflicts CASCADE;
DROP TABLE IF EXISTS bank_configuration CASCADE;
DROP TABLE IF EXISTS bundle_pricing_link CASCADE;
DROP TABLE IF EXISTS bundle_product_link CASCADE;
DROP TABLE IF EXISTS feature_component CASCADE;
DROP TABLE IF EXISTS price_value CASCADE;
DROP TABLE IF EXISTS pricing_component CASCADE;
DROP TABLE IF EXISTS pricing_input_metadata CASCADE;
DROP TABLE IF EXISTS pricing_tier CASCADE;
DROP TABLE IF EXISTS product CASCADE;
DROP TABLE IF EXISTS product_bundle CASCADE;
DROP TABLE IF EXISTS product_category CASCADE;
DROP TABLE IF EXISTS product_feature_link CASCADE;
DROP TABLE IF EXISTS product_pricing_link CASCADE;
DROP TABLE IF EXISTS product_type CASCADE;
DROP TABLE IF EXISTS role CASCADE;
DROP TABLE IF EXISTS role_authority CASCADE;
DROP TABLE IF EXISTS tier_condition CASCADE;

create table bank_category_conflicts (config_id bigint not null, category_a varchar(100) not null, category_b varchar(100) not null, bank_id varchar(255) not null);
create table bank_configuration (allow_multi_bundle_product boolean not null, created_at timestamp(6) not null, id bigint generated by default as identity, updated_at timestamp(6), bank_id varchar(50) not null, admin_email varchar(255), admin_name varchar(255), client_id varchar(255) not null, client_secret varchar(255), created_by varchar(255), currency_code varchar(255) not null, issuer_url varchar(255) not null, name varchar(255), status varchar(255) not null check (status in ('DRAFT','ACTIVE','REJECTED','INACTIVE')), updated_by varchar(255), primary key (id), constraint uk_bank_id unique (bank_id), constraint uk_issuer_client_combination unique (issuer_url, client_id), unique (bank_id, id));
create table bundle_pricing_link (effective_date date, expiry_date date, fixed_value numeric(38,2), use_rules_engine boolean not null, created_at timestamp(6) not null, id bigint generated by default as identity, pricing_component_id bigint not null, product_bundle_id bigint not null, updated_at timestamp(6), bank_id varchar(50) not null, created_by varchar(255), fixed_value_type varchar(255) check (fixed_value_type in ('FEE_ABSOLUTE','FEE_PERCENTAGE','DISCOUNT_PERCENTAGE','DISCOUNT_ABSOLUTE','FREE_COUNT')), updated_by varchar(255), primary key (id));
create table bundle_product_link (is_main_account boolean not null, is_mandatory boolean not null, created_at timestamp(6) not null, id bigint generated by default as identity, product_bundle_id bigint not null, product_id bigint not null, updated_at timestamp(6), bank_id varchar(50) not null, created_by varchar(255), updated_by varchar(255), primary key (id), constraint UK_bundle_product_link_unique unique (product_bundle_id, product_id));
create table feature_component (activation_date date, expiry_date date, version integer not null, created_at timestamp(6) not null, id bigint generated by default as identity, updated_at timestamp(6), status varchar(20) not null check (status in ('DRAFT','ACTIVE','INACTIVE','ARCHIVED')), bank_id varchar(50) not null, code varchar(100) not null, created_by varchar(255), data_type varchar(255) check (data_type in ('STRING','INTEGER','BOOLEAN','DECIMAL','DATE')), name varchar(255) not null, updated_by varchar(255), primary key (id), unique (bank_id, code, version));
create table price_value (raw_value numeric(38,2) not null, created_at timestamp(6) not null, id bigint generated by default as identity, pricing_tier_id bigint not null, updated_at timestamp(6), bank_id varchar(50) not null, created_by varchar(255), updated_by varchar(255), value_type varchar(255) check (value_type in ('FEE_ABSOLUTE','FEE_PERCENTAGE','DISCOUNT_PERCENTAGE','DISCOUNT_ABSOLUTE','FREE_COUNT')), primary key (id));
create table pricing_component (activation_date date, expiry_date date, pro_rata_applicable boolean not null, version integer not null, created_at timestamp(6) not null, id bigint generated by default as identity, updated_at timestamp(6), status varchar(20) not null check (status in ('DRAFT','ACTIVE','INACTIVE','ARCHIVED')), bank_id varchar(50) not null, code varchar(100) not null, created_by varchar(255), description varchar(255), name varchar(255) not null, type varchar(255) check (type in ('FEE','INTEREST_RATE','WAIVER','BENEFIT','DISCOUNT','PACKAGE_FEE','TAX')), updated_by varchar(255), primary key (id), unique (bank_id, code, version));
create table pricing_input_metadata (created_at timestamp(6) not null, id bigint generated by default as identity, updated_at timestamp(6), source_type varchar(30) not null check (source_type in ('FACT_FIELD','CUSTOM_ATTRIBUTE')), bank_id varchar(50) not null, attribute_key varchar(255) not null, created_by varchar(255), data_type varchar(255) not null, display_name varchar(255), source_field varchar(255) not null, updated_by varchar(255), primary key (id), unique (bank_id, attribute_key));
create table pricing_tier (apply_charge_on_full_breach boolean not null, max_threshold numeric(38,2), min_threshold numeric(38,2), priority integer not null, created_at timestamp(6) not null, id bigint generated by default as identity, pricing_component_id bigint not null, updated_at timestamp(6), bank_id varchar(50) not null, code varchar(100) not null, created_by varchar(255), name varchar(255) not null, updated_by varchar(255), primary key (id));
create table product (activation_date date, display_order integer, expiry_date date, is_featured boolean, version integer not null, created_at timestamp(6) not null, id bigint generated by default as identity, product_type_id bigint not null, updated_at timestamp(6), status varchar(20) not null check (status in ('DRAFT','ACTIVE','INACTIVE','ARCHIVED')), bank_id varchar(50) not null, code varchar(100) not null, tagline varchar(100), icon_url varchar(500), full_description varchar(2000), category varchar(255) not null, created_by varchar(255), name varchar(255) not null, target_customer_segments varchar(255), terms_and_conditions TEXT, updated_by varchar(255), primary key (id), unique (bank_id, code, version));
create table product_bundle (activation_date date, expiry_date date, version integer not null, created_at timestamp(6) not null, id bigint generated by default as identity, updated_at timestamp(6), status varchar(20) not null check (status in ('DRAFT','ACTIVE','INACTIVE','ARCHIVED')), bank_id varchar(50) not null, code varchar(100) not null, description varchar(500), created_by varchar(255), name varchar(255) not null, target_customer_segments varchar(255) not null, updated_by varchar(255), primary key (id), unique (bank_id, code, version));
create table product_category (created_at timestamp(6) not null, id bigint generated by default as identity, updated_at timestamp(6), bank_id varchar(50) not null, code varchar(100) not null, name varchar(200) not null, created_by varchar(255), updated_by varchar(255), primary key (id), unique (bank_id, code));
create table product_feature_link (created_at timestamp(6) not null, feature_component_id bigint not null, id bigint generated by default as identity, product_id bigint not null, updated_at timestamp(6), bank_id varchar(50) not null, feature_value varchar(1000) not null, created_by varchar(255), updated_by varchar(255), primary key (id), constraint UK_product_feature_link unique (product_id, feature_component_id));
create table product_pricing_link (effective_date date, expiry_date date, fixed_value numeric(38,2), use_rules_engine boolean not null, created_at timestamp(6) not null, id bigint generated by default as identity, pricing_component_id bigint not null, product_id bigint not null, updated_at timestamp(6), bank_id varchar(50) not null, created_by varchar(255), fixed_value_type varchar(255) check (fixed_value_type in ('FEE_ABSOLUTE','FEE_PERCENTAGE','DISCOUNT_PERCENTAGE','DISCOUNT_ABSOLUTE','FREE_COUNT')), target_component_code varchar(255), updated_by varchar(255), primary key (id));
create table product_type (created_at timestamp(6) not null, id bigint generated by default as identity, updated_at timestamp(6), status varchar(20) default 'DRAFT' not null check (status in ('DRAFT','ACTIVE','INACTIVE','ARCHIVED')), bank_id varchar(50) not null, code varchar(100) not null, created_by varchar(255), name varchar(255) not null, updated_by varchar(255), primary key (id), unique (bank_id, code));
create table role (created_at timestamp(6) not null, id bigint generated by default as identity, updated_at timestamp(6), bank_id varchar(50) not null, name varchar(50) not null, created_by varchar(255), updated_by varchar(255), primary key (id), unique (bank_id, name));
create table role_authority (role_id bigint not null, authority_name varchar(100) not null, primary key (role_id, authority_name));
create table tier_condition (created_at timestamp(6) not null, id bigint generated by default as identity, pricing_tier_id bigint not null, updated_at timestamp(6), bank_id varchar(50) not null, attribute_name varchar(255) not null, attribute_value varchar(255) not null, connector varchar(255) check (connector in ('AND','OR')), created_by varchar(255), operator varchar(255) not null check (operator in ('EQ','NE','GT','GE','LT','LE','IN')), updated_by varchar(255), primary key (id));
create index idx_pricing_tier_code on pricing_tier (code);
